/**
 * Path normalization and safety checks for object keys.
 * Keeps upload/read/delete behavior consistent and rejects traversal-style input.
 */

export type PathValidationResult =
  | { ok: true; path: string }
  | { ok: false; code: 'INVALID_OBJECT_PATH'; error: string };

const MAX_PATH_LENGTH = 1024;
const MAX_SEGMENT_LENGTH = 255;
const ENCODED_SEPARATOR_PATTERN = /%(2f|2F|5c|5C|00)/;

export function normalizeObjectPath(rawPath: string | undefined | null): PathValidationResult {
  const candidate = (rawPath || '').trim();

  if (!candidate) {
    return {
      ok: false,
      code: 'INVALID_OBJECT_PATH',
      error: 'Object path is required.',
    };
  }

  if (candidate.length > MAX_PATH_LENGTH) {
    return {
      ok: false,
      code: 'INVALID_OBJECT_PATH',
      error: `Object path is too long. Maximum length is ${MAX_PATH_LENGTH} characters.`,
    };
  }

  if (candidate.startsWith('/') || candidate.endsWith('/')) {
    return {
      ok: false,
      code: 'INVALID_OBJECT_PATH',
      error: 'Object path must not start or end with "/".',
    };
  }

  if (ENCODED_SEPARATOR_PATTERN.test(candidate)) {
    return {
      ok: false,
      code: 'INVALID_OBJECT_PATH',
      error: 'Encoded path separators are not allowed in object paths.',
    };
  }

  const segments = candidate.split('/');
  const normalizedSegments: string[] = [];

  for (const encodedSegment of segments) {
    if (!encodedSegment) {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: 'Empty path segments are not allowed.',
      };
    }

    let segment: string;
    try {
      segment = decodeURIComponent(encodedSegment);
    } catch {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: 'Object path contains invalid URL encoding.',
      };
    }

    if (segment === '.' || segment === '..') {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: 'Object path traversal segments are not allowed.',
      };
    }

    if (segment.includes('\\')) {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: 'Backslashes are not allowed in object paths.',
      };
    }

    if (segment.includes('\0')) {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: 'Null bytes are not allowed in object paths.',
      };
    }

    if (segment.length > MAX_SEGMENT_LENGTH) {
      return {
        ok: false,
        code: 'INVALID_OBJECT_PATH',
        error: `Object path segment is too long. Maximum segment length is ${MAX_SEGMENT_LENGTH}.`,
      };
    }

    normalizedSegments.push(segment);
  }

  const normalizedPath = normalizedSegments.join('/');

  if (normalizedPath.length > MAX_PATH_LENGTH) {
    return {
      ok: false,
      code: 'INVALID_OBJECT_PATH',
      error: `Object path is too long. Maximum length is ${MAX_PATH_LENGTH} characters.`,
    };
  }

  return { ok: true, path: normalizedPath };
}

/**
 * Extract wildcard object path safely from Hono route params with fallback parsing.
 */
export function extractObjectPathFromRequest(
  requestPath: string,
  wildcardPath: string | undefined,
): PathValidationResult {
  let candidatePath = wildcardPath || '';

  if (!candidatePath) {
    const match = requestPath.match(/\/object\/[^/]+\/(.+)$/);
    candidatePath = match ? match[1] : '';
  }

  return normalizeObjectPath(candidatePath);
}

